{
  "terms": [
    {
      "term": "Generation",
      "simpleDefinition": "The process of converting primary energy sources, like gas, wind, or nuclear, into electrical energy.",
      "anchor": "The 'start line' of the electrical supply chain where energy is first created.",
      "misconception": "Thinking electricity is 'made' from nothing; it is always converted from another energy source like heat or movement."
    },
    {
      "term": "Transmission",
      "simpleDefinition": "The bulk movement of electricity over long distances at very high voltages.",
      "anchor": "The 'motorway' system of the electrical grid, moving power from stations to cities.",
      "misconception": "Confusing transmission with distribution; transmission is only the high-voltage long-distance stage."
    },
    {
      "term": "Transmission Voltages",
      "simpleDefinition": "The specific high-voltage levels used in the UK grid: 400 kV, 275 kV, and 132 kV.",
      "anchor": "The 'Big Three' voltages used for long-distance travel on pylons.",
      "misconception": "Believing that 11 kV or 33 kV are transmission voltages; those are actually lower distribution voltages."
    },
    {
      "term": "Micro-generation",
      "simpleDefinition": "Small-scale production of heat or electricity by individual consumers for their own use.",
      "anchor": "Generating power exactly where it is going to be used, like solar panels on a house roof.",
      "misconception": "Assuming micro-generation always means being 'off-grid'; most systems are still connected to the main network."
    },
    {
      "term": "I²R Loss",
      "simpleDefinition": "Energy lost as heat when current flows through the resistance of a cable.",
      "anchor": "The reason we use high voltage: to keep current low and prevent cables from wasting energy as heat.",
      "misconception": "Thinking high voltage is used because it is 'faster' or 'stronger' rather than for efficiency."
    }
  ],
  "anchorPhrases": [
    "400 kV, 275 kV, and 132 kV",
    "High voltage, low current",
    "Point of consumption",
    "Large-scale generation",
    "Step-up for transmission"
  ],
  "misconceptionTargets": [
    "Confusing 132 kV transmission with 33 kV distribution.",
    "Believing high voltage is used to increase speed rather than reduce heat loss.",
    "Thinking all renewable energy is classified as micro-generation.",
    "Assuming generation and distribution are the same stage of the network."
  ]
}

{
  "teachChecks": [
    {
      "title": "The National Grid Overview",
      "basicQuestions": [
        {
          "questionText": "What is the first stage in the electrical supply chain where energy is converted into electricity?",
          "answerGuidance": [
            "Generation",
            "Power generation"
          ],
          "hint": "It is the process of creating electricity at a power station.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Which network links power stations directly to the consumers who use the electricity?",
          "answerGuidance": [
            "National Grid",
            "The National Grid"
          ],
          "hint": "It is the entire system connecting the source to the user.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Which specific phase of the supply chain is responsible for moving bulk power over long distances?",
          "answerGuidance": [
            "Transmission",
            "Transmission phase"
          ],
          "hint": "Think of the 'motorway' stage of the grid.",
          "sourceTeachingPointIds": [
            "TP3",
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why is the transmission phase described as a 'high-speed motorway system' for electricity?",
      "deeperAnswerGuidance": [
        "It moves bulk power across the country",
        "It connects distant power stations to local areas",
        "It handles long-distance transport efficiently",
        "It acts as a primary backbone for the network"
      ],
      "deeperSourceTeachingPointIds": [
        "TP4",
        "TP5"
      ],
      "hint": "Consider the distance and the volume of power being moved."
    },
    {
      "title": "Transmission Voltage Levels",
